#!/bin/bash
set -e
set -o pipefail

# inject-substrate.sh for effortless-entity-framework execution substrate
#
# Licensed Effortless substrate. The C# Entity Framework DataClasses are
# generated by the `airtabletoodxml` + `odxmltoefdataclasses` transpilers
# (configured in effortless.json with RelativePath:
# /licensed-effortless-tools/entity-framework-dotnet). When the rulebook
# changes, `effortless -buildLocal` regenerates the C# code; this substrate's
# runner picks it up automatically via globbed Compile includes in
# EffortlessEntityFrameworkRunner.csproj.

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
if [ -n "$ERB_DOMAIN_DIR" ] && [ -d "$ERB_DOMAIN_DIR/entity-framework" ]; then
    EF_TOOL_DIR="$ERB_DOMAIN_DIR/entity-framework"
else
    EF_TOOL_DIR="$PROJECT_ROOT/licensed-effortless-tools/entity-framework-dotnet"
fi
export EF_TOOL_DIR
mkdir -p "$EF_TOOL_DIR"

echo "=== Effortless-EntityFramework Substrate: Regenerating from rulebook ==="
echo "  EF tool dir: $EF_TOOL_DIR"

if command -v effortless &> /dev/null; then
    cd "$EF_TOOL_DIR"
    effortless -buildLocal
else
    echo "Warning: effortless CLI not installed, skipping regeneration"
    echo "Install effortless or run 'effortless build' from project root"
fi

cd "$SCRIPT_DIR"

"$SCRIPT_DIR/take-test.sh"
